import java.nio.charset.StandardCharsets;
import java.util.*;

class Solution {
    public static void main(String[] args) throws Exception {
        String text = new String(System.in.readAllBytes(), StandardCharsets.UTF_8).strip();
        int[] values = text.isEmpty() ? new int[0] : Arrays.stream(text.split("\\s+")).mapToInt(Integer::parseInt).toArray();
        List<Integer> list = new ArrayList<>();
        Map<Integer, Integer> counts = new HashMap<>();
        Set<Integer> unique = new HashSet<>();
        for (int value : values) {
            list.add(value);
            counts.merge(value, 1, Integer::sum);
            unique.add(value);
        }
        int sum = counts.entrySet().stream().mapToInt(entry -> entry.getKey() * entry.getValue()).sum();
        System.out.println(sum + ":" + list.size() + ":" + unique.size());
    }
}

