import java.nio.charset.StandardCharsets;
import java.util.*;

class Solution {
    record User(String name, int score) {}

    public static void main(String[] args) throws Exception {
        String[] parts = new String(System.in.readAllBytes(), StandardCharsets.UTF_8).strip().split("\\s+");
        List<User> users = new ArrayList<>();
        for (int i = 0; i < parts.length; i += 2) users.add(new User(parts[i], Integer.parseInt(parts[i + 1])));
        users.sort(Comparator.comparingInt(User::score).reversed().thenComparing(User::name));
        User best = users.get(0);
        System.out.println(best.name() + ":" + best.score());
    }
}

