import java.nio.charset.StandardCharsets;

class Solution {
    sealed interface Shape permits Rect, Circle, Dot {}
    record Rect(int width, int height) implements Shape {}
    record Circle(int radius) implements Shape {}
    record Dot() implements Shape {}

    static int metric(Shape shape) {
        return switch (shape) {
            case Rect(int width, int height) -> width * height;
            case Circle(int radius) -> radius * 2;
            case Dot() -> 0;
        };
    }

    public static void main(String[] args) throws Exception {
        String[] parts = new String(System.in.readAllBytes(), StandardCharsets.UTF_8).strip().split("\\s+");
        Shape shape = switch (parts[0]) {
            case "rect" -> new Rect(Integer.parseInt(parts[1]), Integer.parseInt(parts[2]));
            case "circle" -> new Circle(Integer.parseInt(parts[1]));
            default -> new Dot();
        };
        System.out.println(metric(shape));
    }
}

