import java.nio.charset.StandardCharsets;
import java.util.*;

class Solution {
    record User(String name, int score) {}

    static User choose(List<User> users) {
        Comparator<User> order = Comparator.comparingInt(User::score).reversed().thenComparing(User::name);
        return users.stream().sorted(order).findFirst().orElse(new User("none", 0));
    }

    static void check(boolean condition, String message) {
        if (!condition) throw new AssertionError(message);
    }

    public static void main(String[] args) throws Exception {
        String text = new String(System.in.readAllBytes(), StandardCharsets.UTF_8).strip();
        List<User> users = new ArrayList<>();
        if (!text.isEmpty()) {
            String[] parts = text.split("\\s+");
            for (int i = 0; i < parts.length; i += 2) users.add(new User(parts[i], Integer.parseInt(parts[i + 1])));
        }
        check(choose(List.of()).equals(new User("none", 0)), "empty fallback");
        User winner = choose(users);
        System.out.println(winner.name() + ":" + winner.score());
    }
}
